import os
import ctypes
import time


def disable_console_close():
    """Блокирует кнопку закрытия окна консоли"""
    # Получаем handle текущего окна консоли
    hwnd = ctypes.windll.kernel32.GetConsoleWindow()
    # Убираем кнопку закрытия (меняем стиль окна)
    ctypes.windll.user32.DeleteMenu(
        ctypes.windll.user32.GetSystemMenu(hwnd, False),
        0xF060,  # SC_CLOSE
        0x00000000
    )
    ctypes.windll.user32.DrawMenuBar(hwnd)


def show_unclosable_ascii(ascii_art):
    """Показывает ASCII-арт в незакрываемом окне"""
    disable_console_close()
    os.system('cls')
    print(ascii_art)
    # Бесконечный цикл - программа не завершится
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        # Ctrl+C всё равно работает, но можно и его заблокировать
        while True:
            time.sleep(1)


